// Daily Mate puzzles — Stockfish-verified mate-in-2/3/4 positions sourced from
// the Lichess puzzle database and re-checked locally with Stockfish 17 (`go mate N`).
// The pool is large enough to guarantee a NEW puzzle every day for more than a
// full year before any repeat. Rotation is deterministic: every UTC day everyone
// sees the same puzzle, and within a 365-day cycle no puzzle repeats.

export interface DailyMate {
  id: string;
  fen: string;             // Position with side-to-move = the solver
  side: "w" | "b";         // Who delivers mate
  matesIn: 1 | 2 | 3 | 4;
  /** Acceptable first moves in SAN. */
  firstMoves: string[];
  /** Lichess puzzle rating (difficulty hint). */
  rating?: number;
  /** Optional human-readable name */
  name?: string;
}

