/** Mulberry32 PRNG seeded for deterministic per-cycle shuffles. */
function mulberry32(seed: number) {
  return function () {
    let t = (seed += 0x6d2b79f5);
    t = Math.imul(t ^ (t >>> 15), t | 1);
    t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

/** Fisher-Yates shuffle of indices [0..n) with seeded PRNG. */
function shuffledIndices(n: number, seed: number): number[] {
  const rng = mulberry32(seed);
  const arr = Array.from({ length: n }, (_, i) => i);
  for (let i = n - 1; i > 0; i--) {
    const j = Math.floor(rng() * (i + 1));
    [arr[i], arr[j]] = [arr[j], arr[i]];
  }
  return arr;
}

const CYCLE = DAILY_MATES.length; // ~389 days before any repeat

/**
 * Today's puzzle — deterministic, non-repeating within each cycle.
 * Each cycle uses a fresh shuffle (different seed), so even after the pool
 * is exhausted the next cycle starts in a different order.
 */
export function getTodaysMate(now: Date = new Date()): DailyMate {
  const utcMidnight = Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate());
  const dayIndex = Math.floor(utcMidnight / 86400000);
  const cycleNum = Math.floor(dayIndex / CYCLE);
  const dayInCycle = dayIndex % CYCLE;
  const order = shuffledIndices(CYCLE, 0x9e3779b1 ^ cycleNum);
  return DAILY_MATES[order[dayInCycle]];
}

/** Seconds until the next UTC midnight rotation. */
export function secondsUntilNextMate(now: Date = new Date()): number {
  const tomorrow = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate() + 1));
  return Math.max(0, Math.floor((tomorrow.getTime() - now.getTime()) / 1000));
}
